				},
			);
			if (!intakeResult.shouldStartBuilder) {
				skippedIssues.push({
					workItemId,
					issueNumber: item.issueNumber,
					reason: "ask_human",
				});
				continue;
			}

			const result = await createClaimedManualRun(client, {
				workItemId,
