export async function runIntakeCurator(
	client: Client,
	workItem: IntakeCuratorWorkItem,
	workItemId: string,
	options: IntakeCuratorOptions = {},
): Promise<IntakeCuratorResult> {
	const existingDecisions = options.existingDecisions ?? [];
	const inputFingerprint = buildIntakeInputFingerprint(workItem);

	const deterministicOutcome = getDeterministicOutcome(workItem);
	const runClassifier = options.classify ?? runCodexIntakeClassification;
