			decisionId: freshDecision.id,
			workerRunId: null,
			outcome: evidence.decision,
			nextAction: evidence.nextAction,
			shouldStartBuilder: evidence.decision === "buildable",
			skippedFreshDuplicate: true,
			inputFingerprint,
			blockerCommentPosted: false,
			classificationReason: evidence.reason,
		};
