	if (!intakeDecisionId || !builderWorkerRunId) {
		return;
	}

	try {
		await createLink(client, {
			workItemId,
			fromNodeType: "decision",
			fromNodeId: intakeDecisionId,
			toNodeType: "worker_run",
			toNodeId: builderWorkerRunId,
			relation: "starts",
			metadata: {
				curatorPhase: "intake",
			},
		});
	} catch {
		return;
	}
}

export function isIntakeBuildable(item: GitHubProjectIssueWorkItem): boolean {
	return isIntakeBuildableWithMinimumInputs(item.issueTitle, item.issueBody);
}

export function buildIntakeInputFingerprint(
	workItem: IntakeCuratorWorkItem,
): string {
	const normalized = {
		issueNumber: workItem.issueNumber,
		issueTitle: (workItem.issueTitle ?? "").trim(),
		issueBody: (workItem.issueBody ?? "").trim(),
		blockedBy: normalizeBlockedBy(workItem.blockedBy).sort(),
		projectStatus: workItem.projectStatus ?? null,
	};

	const canonical = JSON.stringify(normalized);
	return createHash("sha256").update(canonical).digest("hex");
}

function classifyToEvidence(
	classification: IntakeClassification,
): {
	decision: IntakeCuratorOutcome;
	reason: string;
	comment: string;	nextAction?: string;
	policyRuleId: string;
} {
	const reason = classification.reason.trim();
	const blockedBy = classification.blocked_by;
	const isBlockedBy = classification.decision === "blocked_by";
	const comment =
		classification.comment ??
		(classification.decision === "ask_human"
			? `Please add the missing intake details so I can continue. ${reason}`
			: isBlockedBy
					? `Blocked blockers: ${blockedBy.join(", ")}. ${reason}`
					: reason);

	const nextAction =
		classification.next_action?.trim() || classification.comment?.trim() || comment;

	return {
		decision: classification.decision,
		reason,
		comment,
		nextAction,
		policyRuleId:
			classification.decision === "buildable"
				? "intake.codex.buildable"
				: classification.decision === "ask_human"
					? "intake.codex.ask_human"
					: "intake.blocked_by",
	};
}

function isIntakeBuildableWithMinimumInputs(
	issueTitle: string,
	issueBody: string | null,
): boolean {
	const title = (issueTitle ?? "").trim();
	const body = (issueBody ?? "").trim();

	if (title.length < 4) {
		return false;
	}

	if (!body || body.length < 12) {
		return false;
	}

	return true;
}

function getDeterministicOutcome(
	workItem: IntakeCuratorWorkItem,
): IntakeClassification | null {
	const blockedBy = normalizeBlockedBy(workItem.blockedBy);
	if (blockedBy.length > 0) {
		return {
			decision: "blocked_by",
			reason: `Issue is blocked by ${blockedBy.length} item(s).`,
			comment:
				"Please resolve these blockers before this work item can move forward.",
			blocked_by: blockedBy,
			next_action:
				`blocked_by:${blockedBy.join(", ")}`,
		};
	}

	if (!isIntakeBuildable(workItem)) {
		return {
			decision: "ask_human",
			reason:
				"Please add a non-empty title and at least a short body before builder dispatch.",
			comment:
				"Please add a non-empty title and a short description so implementation can start safely.",
			blocked_by: [],
			next_action:
				"Please add required details (title and context) and then rerun intake.",
		};
	}

	return null;
}

async function classifyWithHealing(
	workItem: IntakeCuratorWorkItem,
	runner: IntakeClassifierRunner,
	nowMs: number,
	codeModel = DEFAULT_CLASSIFIER_MODEL,
	schemaFilePath?: string,
): Promise<IntakeClassification> {
	let lastError: unknown = null;

	for (let attempt = 1; attempt <= 2; attempt += 1) {
		try {
			const prompt = buildIntakeClassificationPrompt(workItem);
			const schemaPath = await ensureIntakeClassificationSchemaFile(schemaFilePath);
			const outputMessagePath = buildOutputMessagePath();
			const result = await runner({
				workItem,
				prompt,
				schemaFilePath: schemaPath,
				outputMessagePath,
				classificationAttempt: attempt,
				nowMs,
			});
			return intakeClassificationSchema.parse(result.classification);
		} catch (error) {
			lastError = error;
			if (attempt >= 2) {
				return {
					decision: "ask_human",
					reason: buildClassifierFallbackReason({
						error: error,
						workItem,
					}),
					blocked_by: normalizeBlockedBy(workItem.blockedBy),
					comment:
						"The automated intake classifier could not produce a valid result. Please respond with clearer, scoped work request details.",
					next_action:
						"please provide clearer task acceptance criteria and dependencies",
				};
			}
		}
	}

	throw lastError;
}

async function runCodexIntakeClassification(
	input: Parameters<IntakeClassifierRunner>[0],
): Promise<{ classification: IntakeClassification; raw: string; command: string }> {
	const command = buildCodexExecCommand({
		cwd: process.cwd(),
		prompt: input.prompt,
		sandboxMode: "workspace-write",
		approvalPolicy: "never",
		json: true,
		skipGitRepoCheck: true,
		timeoutMs: DEFAULT_CLASSIFIER_TIMEOUT_MS,
		outputSchemaFile: input.schemaFilePath,
		outputLastMessageFile: input.outputMessagePath,
		configOverrides: {
			model: DEFAULT_CLASSIFIER_MODEL,
		},
	});
	const codexResult = await runCodexExec(command);
	const raw = await readFile(input.outputMessagePath, "utf8");

	if (codexResult.exitCode !== 0 || codexResult.timedOut || codexResult.error) {
		throw new Error(
			`Codex classification execution failed: ${codexResult.exitCode ?? "no code"}, timedOut=${codexResult.timedOut}`,
		);
	}

	return {
		classification: parseClassifierOutput(raw),
		raw,
		command: JSON.stringify(command.argv),
	};
}

function parseClassifierOutput(raw: string): IntakeClassification {
	const trimmed = raw.trim();
	if (!trimmed) {
		throw new Error("Codex output was empty.");
	}

	try {
		const parsed = JSON.parse(trimmed);
		if (typeof parsed === "string") {
			return intakeClassificationSchema.parse(JSON.parse(parsed));
		}

		if (parsed && typeof parsed === "object" && "content" in parsed) {
			return intakeClassificationSchema.parse((parsed as { content?: string }).content);
		}
	}
	catch {
		return intakeClassificationSchema.parse(JSON.parse(trimmed));
	}

	throw new Error("Invalid intake classifier output.");
}

function buildClassifierFallbackReason(input: {
	error: unknown;
	workItem: IntakeCuratorWorkItem;
}): string {
	if (input.error instanceof ZodError) {
		return `Intake classification did not match schema: ${input.error.issues.length} validation issue(s).`; 
	}

	if (input.error instanceof Error) {
		return `Intake classification failed during automated review: ${input.error.message}`;
	}

	return `Intake classification failed for #${input.workItem.issueNumber}.`;
}

function buildIntakeClassificationPrompt(workItem: IntakeCuratorWorkItem): string {
	const body = workItem.issueBody?.trim() ?? "";
	return [
		"You are a strict intake classification assistant for Rhapsody.",
		"Return only JSON matching the provided output schema.",
		"Classify whether this issue can be started by the builder now.",
		"Rules:",
		"- buildable: ready to build with current title/body and no clear blockers",
		"- ask_human: unclear requirements, missing constraints, or ambiguous behavior",
		"- blocked_by: explicit blockers are blocking this issue",
		"- prefer ask_human over buildable when safety is unclear",
		"Issue title:",
		`	${workItem.issueTitle}`,
		"Issue body:",
		`	${body.length ? body : "(empty)"}`,
		"Blocked by:",
		`	${normalizeBlockedBy(workItem.blockedBy).join(", ") || "(none)"}`,
		"Output exactly one JSON object with keys: decision, reason, comment?, blocked_by, next_action?",
		"Use non-empty reason text for any non-buildable path.",
	].join("\n");
}

function buildIntakeIssueComment(input: {
	issueTitle: string;
	issueNumber: number;
	body: string;
	comment: string;
	outcome: IntakeCuratorOutcome;
	nextAction?: string;
}): string {
	const title = input.issueTitle.trim();
	const details = [
		`Intake result: ${input.outcome} for #${input.issueNumber} (${title}).`,
		input.body,
		input.comment,
		input.nextAction ? `Next action: ${input.nextAction}` : "",
	].filter(Boolean);
	return details.join("\n\n");
}

function normalizeBlockedBy(blockedBy: string[] | undefined): string[] {
	if (!Array.isArray(blockedBy) || blockedBy.length === 0) {
		return [];
	}

	return Array.from(new Set(blockedBy.filter((value) => typeof value === "string" && value.trim()))).sort();
}

function ensureIntakeClassificationSchemaFile(schemaFilePath?: string): Promise<string> {
	if (schemaFilePath) {
		return Promise.resolve(schemaFilePath);
	}

	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-schema-"));
	const resolvedPath = path.join(dir, "intake-classification.schema.json");
	return writeFile(
		resolvedPath,
		JSON.stringify(intakeClassificationJsonSchema, null, 2),
		"utf8",
	).then(() => resolvedPath);
}

function buildOutputMessagePath(): string {
	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-output-"));
	return path.join(dir, "intake-classification.output.json");
}

function findFreshIntakeDecision(input: {
	decisions: Decision[];
	inputFingerprint: string;
}): Decision | null {
	return (
		input.decisions.find((decision) => {
			if (decision.phase !== "intake") {
				return false;
			}

			const evidence = asRecord(decision.evidence);
			return evidence?.inputFingerprint === input.inputFingerprint;
		}) ?? null
	);
}

function asRecord(value: unknown): Record<string, unknown> | null {
	return typeof value === "object" && value !== null
		? (value as Record<string, unknown>)
		: null;
}
