		approvalPolicy: "never",
		json: true,
		skipGitRepoCheck: true,
		timeoutMs: DEFAULT_CLASSIFIER_TIMEOUT_MS,
		outputSchemaFile: input.schemaFilePath,
		outputLastMessageFile: input.outputMessagePath,
		configOverrides: {
			model: DEFAULT_CLASSIFIER_MODEL,
		},
	});
	const codexResult = await runCodexExec(command);
	const raw = await readFile(input.outputMessagePath, "utf8");

	if (codexResult.exitCode !== 0 || codexResult.timedOut || codexResult.error) {
		throw new Error(
			`Codex classification execution failed: ${codexResult.exitCode ?? "no code"}, timedOut=${codexResult.timedOut}`,
		);
	}

	return {
		classification: parseClassifierOutput(raw),
		raw,
		command: JSON.stringify(command.argv),
	};
}

function parseClassifierOutput(raw: string): IntakeClassification {
	const trimmed = raw.trim();
	if (!trimmed) {
		throw new Error("Codex output was empty.");
	}

	try {
		const parsed = JSON.parse(trimmed);
		if (typeof parsed === "string") {
			return intakeClassificationSchema.parse(JSON.parse(parsed));
		}

		if (parsed && typeof parsed === "object" && "content" in parsed) {
			return intakeClassificationSchema.parse((parsed as { content?: string }).content);
		}
	}
	catch {
		return intakeClassificationSchema.parse(JSON.parse(trimmed));
	}

	throw new Error("Invalid intake classifier output.");
}

function buildClassifierFallbackReason(input: {
	error: unknown;
	workItem: IntakeCuratorWorkItem;
}): string {
	if (input.error instanceof ZodError) {
		return `Intake classification did not match schema: ${input.error.issues.length} validation issue(s).`; 
	}

	if (input.error instanceof Error) {
		return `Intake classification failed during automated review: ${input.error.message}`;
	}

	return `Intake classification failed for #${input.workItem.issueNumber}.`;
}

function buildIntakeClassificationPrompt(workItem: IntakeCuratorWorkItem): string {
	const body = workItem.issueBody?.trim() ?? "";
	return [
		"You are a strict intake classification assistant for Rhapsody.",
		"Return only JSON matching the provided output schema.",
		"Classify whether this issue can be started by the builder now.",
		"Rules:",
		"- buildable: ready to build with current title/body and no clear blockers",
		"- ask_human: unclear requirements, missing constraints, or ambiguous behavior",
		"- blocked_by: explicit blockers are blocking this issue",
		"- prefer ask_human over buildable when safety is unclear",
		"Issue title:",
		`	${workItem.issueTitle}`,
		"Issue body:",
		`	${body.length ? body : "(empty)"}`,
		"Blocked by:",
		`	${normalizeBlockedBy(workItem.blockedBy).join(", ") || "(none)"}`,
		"Output exactly one JSON object with keys: decision, reason, comment?, blocked_by, next_action?",
		"Use non-empty reason text for any non-buildable path.",
	].join("\n");
}

function buildIntakeIssueComment(input: {
	issueTitle: string;
	issueNumber: number;
	body: string;
	comment: string;
	outcome: IntakeCuratorOutcome;
	nextAction?: string;
}): string {
	const title = input.issueTitle.trim();
	const details = [
		`Intake result: ${input.outcome} for #${input.issueNumber} (${title}).`,
		input.body,
		input.comment,
		input.nextAction ? `Next action: ${input.nextAction}` : "",
	].filter(Boolean);
	return details.join("\n\n");
}

function normalizeBlockedBy(blockedBy: string[] | undefined): string[] {
	if (!Array.isArray(blockedBy) || blockedBy.length === 0) {
		return [];
	}

	return Array.from(new Set(blockedBy.filter((value) => typeof value === "string" && value.trim()))).sort();
}

function ensureIntakeClassificationSchemaFile(schemaFilePath?: string): Promise<string> {
	if (schemaFilePath) {
		return Promise.resolve(schemaFilePath);
	}

	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-schema-"));
	const resolvedPath = path.join(dir, "intake-classification.schema.json");
	return writeFile(
		resolvedPath,
		JSON.stringify(intakeClassificationJsonSchema, null, 2),
		"utf8",
	).then(() => resolvedPath);
}

function buildOutputMessagePath(): string {
	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-output-"));
	return path.join(dir, "intake-classification.output.json");
}

function findFreshIntakeDecision(input: {
	decisions: Decision[];
	inputFingerprint: string;
}): Decision | null {
	return (
		input.decisions.find((decision) => {
			if (decision.phase !== "intake") {
				return false;
			}

			const evidence = asRecord(decision.evidence);
			return evidence?.inputFingerprint === input.inputFingerprint;
		}) ?? null
	);
}

function asRecord(value: unknown): Record<string, unknown> | null {
	return typeof value === "object" && value !== null
		? (value as Record<string, unknown>)
		: null;
}

