export function isIntakeBuildable(item: GitHubProjectIssueWorkItem): boolean {
	const title = (item.issueTitle ?? "").trim();
	const body = (item.issueBody ?? "").trim();

	if (title.length < 4) {
		return false;
	}

	if (!body || body.length < 12) {
		return false;
	}

	return true;
