function buildIntakeIssueComment(
	workItem: IntakeCuratorWorkItem,
	classification: IntakeClassification,
): string {
	const lines = [
		`Rhapsody intake classification: ${classification.decision} for #${workItem.issueNumber}`,
		`Reason: ${classification.reason}`,
		`Issue: ${workItem.issueTitle}`,
	];

	if (classification.comment) {
		lines.push(classification.comment);
	}

	const nextAction = pickNextAction(classification);
	if (nextAction) {
		lines.push(`Next action: ${nextAction}`);
	}

	if (classification.blocked_by.length > 0) {
		lines.push(`Blocked by: ${classification.blocked_by.join(", ")}`);
	}

	return lines.join("\n\n");
}

function buildOutputMessagePath(nowMs: number | undefined, attempt: number): string {
	const dir = mkdtempSync(
		path.join(tmpdir(), `rhapsody-intake-classifier-${String(nowMs ?? Date.now())}-`),
	);
	return path.join(dir, `attempt-${attempt}.json`);
}

async function ensureSchemaFile(overriddenPath?: string): Promise<string> {
	if (overriddenPath) {
		return overriddenPath;
	}

	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-schema-"));
	const schemaPath = path.join(dir, "schema.json");
	await writeFile(
		schemaPath,
		JSON.stringify(intakeClassificationJsonSchema, null, 2),
		"utf8",
	);
	return schemaPath;
}

function pickNextAction(classification: IntakeClassification): string | null {
	if (classification.next_action?.trim()) {
		return classification.next_action.trim();
	}
	if (classification.comment?.trim()) {
		return classification.comment.trim();
	}
	return null;
}

function computePolicyRuleId(
	decision: IntakeCuratorOutcome,
	deterministic: IntakeClassification | null,
): string {
	if (deterministic) {
		if (deterministic.decision === "blocked_by") {
			return "intake.blocked_by";
		}
		return "intake.ask_human";
	}

	return decision === "buildable"
		? "intake.codex.buildable"
		: "intake.codex.ask_human";
}

function normalizeBlockedBy(blockedBy: string[] | undefined): string[] {
	if (!Array.isArray(blockedBy) || blockedBy.length === 0) {
		return [];
	}

	return Array.from(
		new Set(
			blockedBy
				.filter((item): item is string => typeof item === "string")
				.map((item) => item.trim())
				.filter(Boolean),
		),
	).sort();
}

function findFreshIntakeDecision(input: {
	decisions: Decision[];
	inputFingerprint: string;
}): Decision | null {
	return (
		input.decisions.find((decision) => {
			if (decision.phase !== "intake") {
				return false;
		}

			const evidence = asRecord(decision.evidence);
			return evidence?.inputFingerprint === input.inputFingerprint;
		}) ?? null
	);
}

function asRecord(value: unknown): Record<string, unknown> | null {
	return typeof value === "object" && value !== null
		? (value as Record<string, unknown>)
		: null;
}

