export type IntakeCuratorOutcome = "buildable" | "ask_human" | "blocked_by";

export const intakeClassificationSchema = z.object({
	decision: z.enum(["buildable", "ask_human", "blocked_by"]),
	reason: z.string().min(1),
	comment: z.string().optional(),
	blocked_by: z.array(z.string().min(1)).default([]),
	next_action: z.string().optional(),
});

