function computePolicyRuleId(
	decision: IntakeCuratorOutcome,
	deterministic: IntakeClassification | null,
): string {
	if (deterministic) {
		if (deterministic.decision === "blocked_by") {
			return "intake.blocked_by";
		}
		return "intake.ask_human";
	}

	return decision === "buildable"
		? "intake.codex.buildable"
		: "intake.codex.ask_human";
}

function normalizeBlockedBy(blockedBy: string[] | undefined): string[] {
	if (!Array.isArray(blockedBy) || blockedBy.length === 0) {
		return [];
	}

	return Array.from(
		new Set(
			blockedBy
				.filter((item): item is string => typeof item === "string")
				.map((item) => item.trim())
				.filter(Boolean),
		),
	).sort();
}

function findFreshIntakeDecision(input: {
	decisions: Decision[];
	inputFingerprint: string;
}): Decision | null {
	return (
		input.decisions.find((decision) => {
			if (decision.phase !== "intake") {
				return false;
			}

			const evidence = asRecord(decision.evidence);
			return evidence?.inputFingerprint === input.inputFingerprint;
		}) ?? null
	);
}

function asRecord(value: unknown): Record<string, unknown> | null {
	return typeof value === "object" && value !== null
		? (value as Record<string, unknown>)
		: null;
}

