		issueNumber: workItem.issueNumber,
		blockedBy: normalizeBlockedBy(workItem.blockedBy),
		projectStatus: workItem.projectStatus ?? null,
	};

	return createHash("sha256").update(JSON.stringify(normalized)).digest("hex");
}

