		},
	});

	const result = await runCodexExec(command);
	if (result.exitCode !== 0 || result.timedOut || result.error) {
		throw new Error(
			`Codex intake classification failed (code=${result.exitCode}, timedOut=${result.timedOut}).`,
		);
	}

	const raw = await readFile(input.outputMessagePath, "utf8");
	return {
		classification: parseClassifierOutput(raw),
		raw,
		command: command.argv.join(" "),
	};
}

function buildClassifierFallbackReason(
	error: unknown,
	workItem: IntakeCuratorWorkItem,
): string {
	if (error instanceof ZodError) {
		return `Automated intake validation failed for #${workItem.issueNumber}.`;
	}

	if (error instanceof Error) {
		return `Automated intake classification failed for #${workItem.issueNumber}: ${error.message}`;
	}

	return `Automated intake classification failed for #${workItem.issueNumber}.`;
}

function inferDeterministicClassification(
	workItem: IntakeCuratorWorkItem,
): IntakeClassification | null {
	const blockedBy = normalizeBlockedBy(workItem.blockedBy);
	if (blockedBy.length > 0) {
		return {
			decision: "blocked_by",
			reason: `Issue is blocked by ${blockedBy.length} item(s): ${blockedBy.join(", ")}`,
			comment:
				"Please resolve these blockers before this issue can be started.",
			blocked_by: blockedBy,
			next_action: `blocked_by:${blockedBy.join(", ")}`,
		};
	}

	if (!isIntakeBuildable(workItem)) {
		return {
			decision: "ask_human",
			reason:
				"Please add a non-empty title and at least a short body before builder dispatch.",
			comment:
				"Please provide a clear description, constraints, and expected outcome.",
			blocked_by: [],
			next_action: "add_context_and_acceptance_criteria",
		};
	}

	return null;
}

function parseClassifierOutput(raw: string): IntakeClassification {
	const trimmed = raw.trim();
	if (!trimmed) {
		throw new Error("Classifier output was empty.");
	}

	const parsed = tryParseJson(trimmed);
	if (!parsed) {
		throw new Error("Classifier output was not parseable JSON.");
	}

	if (
		typeof parsed === "object" &&
		parsed !== null &&
		"content" in parsed &&
		typeof (parsed as { content?: unknown }).content === "string"
	) {
		const nested = tryParseJson((parsed as { content: string }).content);
		if (nested) {
			return intakeClassificationSchema.parse(nested);
		}
	}

	if (typeof parsed === "string") {
		const nested = tryParseJson(parsed);
		if (!nested) {
			throw new Error("Classifier output was not parseable JSON.");
		}
		return intakeClassificationSchema.parse(nested);
	}

	return intakeClassificationSchema.parse(parsed);
}

function tryParseJson(raw: string): unknown {
	try {
		return JSON.parse(raw);
	} catch {
		return null;
	}
}

