		input.status === "canceled" ||
		input.status === "timed_out" ||
		input.status === "stale";
	const startedAt = input.startedAt ?? (isRunning ? now : null);
	const finishedAt = input.finishedAt ?? (isTerminal ? now : null);

	const result = await client.execute({
		sql: `
