	if (
		!payload ||
		(Array.isArray(payload.errors) && payload.errors.length > 0)
	) {
		throw new Error(
			`GitHub GraphQL request returned errors: ${JSON.stringify(payload.errors?.map((error) => error.message))}`,
		);
	}

