export function isIntakeBuildable(item: {
	issueTitle: string;
	issueBody: string | null;
}): boolean {
	const title = (item.issueTitle ?? "").trim();
	const body = (item.issueBody ?? "").trim();

	if (title.length < 4) {
		return false;
