async function ensureSchemaFile(overriddenPath?: string): Promise<string> {
	if (overriddenPath) {
		return overriddenPath;
	}

	const dir = mkdtempSync(path.join(tmpdir(), "rhapsody-intake-schema-"));
	const schemaPath = path.join(dir, "schema.json");
	await writeFile(
