		id: value.id,
		nodeId: value.node_id,
		title: value.title,
		body: value.body,
		htmlUrl: value.html_url,
		state: value.state,
		labels: value.labels.flatMap(normalizeLabel),
	};
}

function normalizeLabel(
	value: GitHubIssueResponse["labels"][number],
): GitHubIssueLabel[] {
	if (typeof value === "string") {
		return [];
	}

	return [
		{
			id: value.id,
			nodeId: value.node_id,
			name: value.name,
			color: value.color,
			description: value.description,
		},
	];
}

type GitHubIssueResponse = {
	number: number;
	id: number;
	node_id: string;
	title: string;
	body: string | null;
	html_url: string;
	state: string;
	labels: (
		| string
		| {
				id: number;
				node_id: string;
				name: string;
				color: string | null;
				description: string | null;
		  }
	)[];
};

function isGitHubIssueResponse(value: unknown): value is GitHubIssueResponse {
	if (typeof value !== "object" || value === null) {
		return false;
	}

	const issue = value as Partial<GitHubIssueResponse>;

	return (
		typeof issue.number === "number" &&
		typeof issue.id === "number" &&
		typeof issue.node_id === "string" &&
		typeof issue.title === "string" &&
		(issue.body === null || typeof issue.body === "string") &&
		typeof issue.html_url === "string" &&
		typeof issue.state === "string" &&
		Array.isArray(issue.labels)
	);
}

async function safeResponseText(response: Response): Promise<string> {
	try {
		return await response.text();
	} catch {
		return `HTTP ${response.status}`;
	}
}

