	command: string;
}> {
	const outputMessagePath = input.outputMessagePath;
	const options = {
		cwd: process.cwd(),
		prompt: input.prompt,
		approvalPolicy: "never" as const,
		sandboxMode: "workspace-write" as const,
		json: true,
