				Authorization: `Bearer ${env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
			},
		},
	);

	if (!response.ok) {
		throw new GitHubIssueFetchError(
			response.status,
			input.owner,
			input.repository,
			input.issueNumber,
		);
	}

	return normalizeIssue(await response.json());
